    for p in positions:
        if p['symbol'] == 'MKRUSD':
            print(f"Found MKRUSD position: {p['qty']} units, avg entry ${p['avg_entry_price']}")
            qty = float(p['qty'])
            # Place market sell order
            order = client.place_market_order('MKRUSD', qty, side='sell')
            if order:
                print(f"Market sell order placed: {order['id']} status {order['status']}")
            else:
                print("Failed to place market sell order")
            break
    else:
        print("No MKRUSD position found")

if __name__ == "__main__":
